/**
 * @fileoverview Accordion constants — CSS classes, ARIA attributes, selectors, defaults.
 * @module module/Accordion/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:     'accordion',
    ITEM:     'accordion-item',
    HEADER:   'accordion-header',
    TRIGGER:  'accordion-trigger',
    ICON:     'accordion-icon',
    PANEL:    'accordion-panel',
    EXPANDED: 'is-expanded',
    DISABLED: 'is-disabled',
});

/** ARIA role values */
export const ARIA = Object.freeze({
    HEADING_LEVEL: '3',
});

/** DOM selectors (support both class and data-attribute markup) */
export const SEL = Object.freeze({
    ROOT:    '.accordion',
    ITEM:    '.accordion-item, [data-accordion-item]',
    HEADER:  '.accordion-header, [data-accordion-header]',
    TRIGGER: '.accordion-trigger, [data-accordion-trigger]',
    PANEL:   '.accordion-panel, [data-accordion-panel]',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    multiple: false,
    activeIndex: null,
    collapsible: true,
    disabled: [],
    variant: null,
    onExpand: null,
    onCollapse: null,
});

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('Accordion', {
    ROOT        : { class: 'accordion-container', aliases: ['accordion', 'root', 'container'] },
    ITEM        : { class: 'accordion-item', aliases: ['item'] },
    HEADER      : { class: 'accordion-header', aliases: ['header'] },
    TRIGGER     : { class: 'accordion-trigger', aliases: ['trigger', 'button'] },
    ICON        : { class: 'accordion-icon', aliases: ['icon', 'chevron'], tag: 'span' },
    PANEL       : { class: 'accordion-panel', aliases: ['panel', 'content'] },
});

PART.ROOT.jit     = 'w-full [border:1px_solid_var(--ac-border)] rounded-[var(--ac-radius)] [font-family:var(--ac-font-stack)] fg-[var(--ac-text)] [&_.accordion-item:first-child_.accordion-trigger]:[border-radius:var(--ac-radius)_var(--ac-radius)_0_0] [&.is-disabled_.accordion-trigger:hover]:[background:transparent]';
PART.ITEM.jit     = 'w-full [border-bottom:1px_solid_var(--ac-border)] last:[border-bottom:none] {is-disabled}:opacity-50 [&.is-disabled_.accordion-trigger]:cursor-not-allowed';
PART.HEADER.jit   = 'w-full';
PART.TRIGGER.jit  = 'w-full flex items-center justify-between gap-[var(--ac-gap)] p-[var(--ac-padding)] bg-transparent [border:none] cursor-pointer fg-[var(--ac-text)] text-[var(--ac-font-size)] font-semibold text-left select-none ' + TRANSITION_COLORS + ' hover:[background:var(--ac-bg-hover)] focus-visible:[outline:2px_solid_var(--ac-accent)] focus-visible:[outline-offset:-2px] focus-visible:z-[1]';
PART.ICON.jit     = 'shrink-0 w-[var(--ac-icon-size)] h-[var(--ac-icon-size)] fg-[var(--ac-icon-color)] [transition:transform_.2s_ease] {is-expanded}:[transform:rotate(180deg)]';
PART.PANEL.jit    = 'overflow-hidden [border-top:none] {is-expanded}:[border-top:1px_solid_var(--ac-border)] p-[var(--ac-padding)] [transition:height_.3s_ease]';