/**
 * @fileoverview Accordion view — DOM setup / teardown and state-machine effects.
 * @module module/Accordion/view
 */

import razyui from '../../index.js';
import { CLS, ARIA, PART } from './constants.js';

// ═══════════════════════════════════════
//  State Machine Effects (DOM updates)
// ═══════════════════════════════════════

export const SM_EFFECTS = {
    /** Entry effect — item is expanded */
    expanded({ trigger, panel, icon }) {
        razyui(trigger).addClass(CLS.EXPANDED).setAttr({ 'aria-expanded': 'true' });
        razyui(panel).addClass(CLS.EXPANDED);
        if (icon) razyui(icon).addClass(CLS.EXPANDED);

        // Animate panel open
        const el = panel instanceof HTMLElement ? panel : panel;
        el.style.padding = '';
        el.style.maxHeight = el.scrollHeight + 'px';
    },

    /** Entry effect — item is collapsed */
    collapsed({ trigger, panel, icon }) {
        razyui(trigger).removeClass(CLS.EXPANDED).setAttr({ 'aria-expanded': 'false' });
        razyui(panel).removeClass(CLS.EXPANDED);
        if (icon) razyui(icon).removeClass(CLS.EXPANDED);

        // Animate panel close
        const el = panel instanceof HTMLElement ? panel : panel;
        el.style.maxHeight = '0px';
        el.style.padding = '0';
    },

    /** Entry effect — item becomes disabled */
    disabled({ trigger, item }) {
        razyui(item).addClass(CLS.DISABLED);
        razyui(trigger).setAttr({ 'aria-disabled': 'true', tabindex: '-1' });
    },

    /** Exit effect — leaving disabled */
    'disabled:exit'({ trigger, item }) {
        razyui(item).removeClass(CLS.DISABLED);
        razyui(trigger).removeAttr('aria-disabled').setAttr({ tabindex: '0' });
    },
};

// ═══════════════════════════════════════
//  DOM Setup
// ═══════════════════════════════════════

/**
 * Set up the root accordion container.
 *
 * @param {Elements} root — razyui-wrapped root element
 */
export function setupRoot(root) {
    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);
}

/**
 * Set up a single accordion item with ARIA attributes.
 *
 * @param {Element} itemEl — the item container element
 * @param {Element} triggerEl — the trigger/button element
 * @param {Element} panelEl — the panel element
 * @param {number} uid — unique accordion instance id
 * @param {number} index — item index
 * @returns {{ item: Element, trigger: Element, panel: Element, icon: Element|null }}
 */
export function setupItemARIA(itemEl, triggerEl, panelEl, uid, index) {
    const item    = razyui(itemEl);
    const trigger = razyui(triggerEl);
    const panel   = razyui(panelEl);

    const triggerId = `accordion-${uid}-trigger-${index}`;
    const panelId   = `accordion-${uid}-panel-${index}`;

    // Item
    PART.ITEM.apply(item);

    // Trigger (button)
    PART.TRIGGER.apply(trigger);
    if (triggerEl.classList.contains(CLS.HEADER) || triggerEl.hasAttribute('data-accordion-header')) {
        PART.HEADER.apply(trigger);
    }
    triggerEl.id = triggerId;
    trigger.setAttr({
        'role': 'button',
        'aria-expanded': 'false',
        'aria-controls': panelId,
        'tabindex': '0',
    });

    // Panel
    PART.PANEL.apply(panel);
    panelEl.id = panelId;
    panel.setAttr({
        'role': 'region',
        'aria-labelledby': triggerId,
    });
    panelEl.style.maxHeight = '0px';
    panelEl.style.padding = '0';
    panelEl.style.overflow = 'hidden';

    // Icon (chevron indicator) — look for existing or create one
    let icon = triggerEl.querySelector('.' + CLS.ICON);
    if (!icon) {
        icon = PART.ICON.create();
        icon[0].innerHTML = '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M4 6l4 4 4-4" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>';
        trigger.append(icon);
        icon = icon[0];
    } else {
        PART.ICON.apply(razyui(icon));
    }

    return { item: itemEl, trigger: triggerEl, panel: panelEl, icon };
}

// ═══════════════════════════════════════
//  DOM Teardown
// ═══════════════════════════════════════

/**
 * Remove all attributes, roles, and classes added by the Accordion.
 *
 * @param {Elements} root
 */
export function cleanupDOM(root) {
    root.removeClass(CLS.ROOT);
    PART.ROOT.unapply(root);

    // Clean up item elements
    const items = root[0].querySelectorAll('.' + CLS.ITEM);
    items.forEach(itemEl => {
        const trigger = itemEl.querySelector('.' + CLS.TRIGGER);
        const panel   = itemEl.querySelector('.' + CLS.PANEL);

        if (trigger) {
            trigger.removeAttribute('aria-expanded');
            trigger.removeAttribute('aria-controls');
            trigger.removeAttribute('aria-disabled');
            trigger.removeAttribute('tabindex');
            trigger.removeAttribute('role');
        }
        if (panel) {
            panel.removeAttribute('role');
            panel.removeAttribute('aria-labelledby');
            panel.style.maxHeight = '';
            panel.style.padding = '';
            panel.style.overflow = '';
        }
    });
}
