/**
 * @fileoverview Accordion helpers — pure utility functions.
 * @module module/Accordion/helpers
 */

/**
 * Find the next enabled item index in a given direction, wrapping around.
 *
 * @param {Array} items — array of header elements
 * @param {number} from — current index
 * @param {number} direction — +1 or -1
 * @param {boolean} [wrap=true] — wrap around the list
 * @returns {number|null} — next enabled index or null
 */
export function findNextItem(items, from, direction, wrap = true) {
    const len = items.length;
    if (!len) return null;

    let idx = from;
    for (let i = 0; i < len; i++) {
        idx += direction;
        if (wrap) {
            idx = ((idx % len) + len) % len;
        } else if (idx < 0 || idx >= len) {
            return null;
        }
        if (!items[idx].disabled && !items[idx].classList.contains('is-disabled')) {
            return idx;
        }
    }
    return null;
}
